import React, { useState, useEffect, useRef } from 'react';
import './Chat.css';

const API_BASE_URL = 'http://localhost:5000';  // Changed from 127.0.0.1

function Chat({ user }) {
    const [messages, setMessages] = useState([]);
    const [input, setInput] = useState("");
    const [isTyping, setIsTyping] = useState(false);
    const [darkMode, setDarkMode] = useState(false);
    const [retentionData, setRetentionData] = useState(null);
    const [isListening, setIsListening] = useState(false);
    const chatEndRef = useRef(null);
    // Persistent session ID for the current chat session (not regenerated per message)
    const sessionIdRef = useRef('web_chat_' + Date.now());

    // Fetch user status (Streaks, Check-ins, Insights)
    const fetchStatus = async () => {
        try {
            const response = await fetch(`${API_BASE_URL}/api/user/status?user_id=${user?.id || 1}`);
            const data = await response.json();
            if (data.status === 'success') {
                setRetentionData(data);

                // FEATURE 4: Inactivity Nudge
                if (data.nudge) {
                    setMessages(prev => [{
                        id: 'nudge-' + Date.now(),
                        text: data.nudge,
                        sender: 'bot'
                    }, ...prev]);
                }
            }
        } catch (err) {
            console.error("Failed to fetch status", err);
        }
    };

    useEffect(() => {
        fetchStatus();
    }, [user]);

    // Set the initial welcome message when the component loads
    useEffect(() => {
        if (user && user.username) {
            setMessages(prev => {
                if (prev.length > 0) return prev;
                return [{
                    id: Date.now(),
                    text: `Welcome back ${user.username}… Day ${user.streak || 1} streak 🔥 Aaj ka mission ready hai.\n\nMere memory ke hisaab se ${user.lastSession || 'pehle'} tum thoda ${user.lastMood || 'low'} feel kar rahe the. Aaj kaisa lag raha hai?`,
                    sender: 'bot'
                }];
            });
        }
    }, [user]);

    // Apply dark mode class to body
    useEffect(() => {
        if (darkMode) {
            document.body.classList.add('dark-mode');
        } else {
            document.body.classList.remove('dark-mode');
        }

        localStorage.setItem('darkMode', darkMode);
    }, [darkMode]);

    // Load dark mode preference
    useEffect(() => {
        const savedDarkMode = localStorage.getItem('darkMode') === 'true';
        setDarkMode(savedDarkMode);
    }, []);

    // Auto scroll
    useEffect(() => {
        chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
    }, [messages, isTyping]);

    // Speech Recognition Setup using useRef to prevent re-render destruction
    const recognitionRef = useRef(null);

    useEffect(() => {
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
        if (SpeechRecognition && !recognitionRef.current) {
            const recognition = new SpeechRecognition();
            recognition.continuous = false;
            recognition.interimResults = true;
            recognitionRef.current = recognition;
        }
    }, []);

    const toggleListening = () => {
        if (!recognitionRef.current) {
            alert("Microphone dictation is not supported in this browser. Please use Google Chrome or Edge.");
            return;
        }

        const recognition = recognitionRef.current;

        if (isListening) {
            recognition.stop();
            setIsListening(false);
        } else {
            // Set up handlers fresh so they have the latest closure
            recognition.onresult = (event) => {
                const transcript = Array.from(event.results)
                    .map(result => result[0].transcript)
                    .join('');
                setInput(transcript);
            };

            recognition.onerror = (event) => {
                console.error("Speech recognition error", event.error);
                setIsListening(false);
            };

            recognition.onend = () => {
                setIsListening(false);
            };

            setInput('');
            try {
                recognition.start();
                setIsListening(true);
            } catch (err) {
                console.error("Failed to start speech recognition:", err);
                setIsListening(false);
            }
        }
    };

    const playAudio = (url) => {
        if (!url) return;
        const fullUrl = url.startsWith('http') ? url : `${API_BASE_URL}${url}`;
        const audio = new Audio(fullUrl);
        audio.play().catch(e => console.error("Audio playback failed:", e));
    };

    const sendMessage = async () => {
        if (!input.trim()) return;

        const userMessage = {
            id: Date.now(),
            text: input,
            sender: 'user'
        };
        setMessages(prev => [...prev, userMessage]);
        setInput("");
        setIsTyping(true);

        try {
            console.log("Sending message to backend...");

            const response = await fetch(`${API_BASE_URL}/api/chat`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Accept': 'application/json'
                },
                body: JSON.stringify({
                    message: input,
                    user_id: user?.id || 1,
                    user_name: user?.username || "Friend",
                    session_id: sessionIdRef.current  // ✅ Persistent session ID
                })
            });

            console.log("Response status:", response.status);

            if (!response.ok) {
                throw new Error(`HTTP error! status: ${response.status}`);
            }

            const data = await response.json();
            console.log("Backend response:", data);

            const botMessage = {
                id: Date.now() + 1,
                text: data.reply || "I'm here for you.",
                sender: 'bot',
                audioUrl: data.audioUrl
            };
            setMessages(prev => [...prev, botMessage]);

        } catch (error) {
            console.error("Chat error:", error);
            const errorMsg = {
                id: Date.now() + 1,
                text: "I'm having trouble connecting. Please check if the backend server is running.",
                sender: 'bot'
            };
            setMessages(prev => [...prev, errorMsg]);
        } finally {
            setIsTyping(false);
        }
    };

    const handleKeyPress = (e) => {
        if (e.key === 'Enter') {
            sendMessage();
        }
    };

    const clearChat = () => {
        if (window.confirm("Are you sure you want to clear all messages?")) {
            setMessages([{
                id: Date.now(),
                text: `Chat cleared. How can I help you today, ${user?.username || 'friend'}?`,
                sender: 'bot'
            }]);
            localStorage.removeItem('chatMessages');
        }
    };

    // Test backend connection
    const testBackend = async () => {
        try {
            const response = await fetch(`${API_BASE_URL}/test`);
            const data = await response.json();
            console.log("Backend test:", data);
            alert(`Backend test: ${data.message}`);
        } catch (error) {
            console.error("Backend test failed:", error);
            alert("Backend connection failed!");
        }
    };

    return (
        <div className={`chat-container ${darkMode ? 'dark-mode' : ''}`}>
            {/* FEATURE 2 & 7: Retention Banner */}
            {retentionData && (
                <div className="retention-banner">
                    <div className="streak-badge">
                        <svg width="18" height="18" viewBox="0 0 24 24" fill="#F59E0B" xmlns="http://www.w3.org/2000/svg">
                            <path d="M12 2C12 2 8 6 8 11.5C8 14.5 9.5 16 12 21C12 21 16 17 16 11.5C16 8 13.5 5.5 12 2Z" fill="#F59E0B" />
                            <path d="M12 11C12 11 10.5 13 10.5 15.5C10.5 17 11.25 18 12 19.5C12 19.5 13.5 17 13.5 15.5C13.5 13.5 12.5 12.5 12 11Z" fill="#FFFBEB" />
                        </svg>
                        {retentionData.streak}-day streak
                        <span className="milestone-text">
                            {retentionData.streak >= 30 ? " ✨ Real growth" :
                                retentionData.streak >= 7 ? " 💪 Showing up" :
                                    retentionData.streak >= 3 ? " 🌱 Habit building" : ""}
                        </span>
                    </div>
                    {retentionData.alone_insight && (
                        <div className="alone-insight">
                            <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor" xmlns="http://www.w3.org/2000/svg">
                                <path d="M12 21.35L10.55 20.03C5.4 15.36 2 12.28 2 8.5C2 5.42 4.42 3 7.5 3C9.24 3 10.91 3.81 12 5.09C13.09 3.81 14.76 3 16.5 3C19.58 3 22 5.42 22 8.5C22 12.28 18.6 15.36 13.45 20.04L12 21.35Z"/>
                            </svg>
                            {retentionData.alone_insight}
                        </div>
                    )}
                </div>
            )}

            <div className="chat-header">
                <div className="chat-header-avatar">M</div>
                <div className="chat-header-info">
                    <h2>MoodMate</h2>
                    <p>I’m here with you.</p>
                </div>
                <div className="chat-header-actions">
                    <button
                        className="header-icon-btn"
                        onClick={testBackend}
                        title="Test backend connection"
                    >
                        <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                            <path d="M14.7 6.3a1 1 0 0 0 0 1.4l1.6 1.6a1 1 0 0 0 1.4 0l3.77-3.77a6 6 0 0 1-7.94 7.94l-6.91 6.91a2.12 2.12 0 0 1-3-3l6.91-6.91a6 6 0 0 1 7.94-7.94l-3.76 3.76z"></path>
                        </svg>
                    </button>
                    <button
                        className="header-icon-btn"
                        onClick={clearChat}
                        title="Clear conversation"
                    >
                        <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                            <polyline points="3 6 5 6 21 6"></polyline>
                            <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
                            <line x1="10" y1="11" x2="10" y2="17"></line>
                            <line x1="14" y1="11" x2="14" y2="17"></line>
                        </svg>
                    </button>
                    <button
                        className="header-icon-btn dark-mode-toggle"
                        onClick={() => setDarkMode(!darkMode)}
                        aria-label="Toggle dark mode"
                    >
                        {darkMode ? (
                            <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                <circle cx="12" cy="12" r="5"></circle>
                                <line x1="12" y1="1" x2="12" y2="3"></line>
                                <line x1="12" y1="21" x2="12" y2="23"></line>
                                <line x1="4.22" y1="4.22" x2="5.64" y2="5.64"></line>
                                <line x1="18.36" y1="18.36" x2="19.78" y2="19.78"></line>
                                <line x1="1" y1="12" x2="3" y2="12"></line>
                                <line x1="21" y1="12" x2="23" y2="12"></line>
                                <line x1="4.22" y1="19.78" x2="5.64" y2="18.36"></line>
                                <line x1="18.36" y1="5.64" x2="19.78" y2="4.22"></line>
                            </svg>
                        ) : (
                            <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                <path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"></path>
                            </svg>
                        )}
                    </button>
                </div>
            </div>

            <div className="chat-box">
                <div style={{ background: 'rgba(239, 68, 68, 0.08)', color: '#ef4444', padding: '10px 20px', fontSize: '12.5px', borderBottom: '1px solid rgba(239, 68, 68, 0.1)', textAlign: 'center', lineHeight: '1.4', backdropFilter: 'blur(5px)' }}>
                    <span style={{fontWeight: 'bold'}}>Safety Note:</span> MoodMate is an AI companion, not a licensed medical professional. If you're in serious distress, please contact a trusted professional helpline.
                </div>
                <div className="chat-messages-container">
                    {messages.map((msg) => (
                        <div key={msg.id} className={`chat-message ${msg.sender}`}>
                            <div className="message-content">
                                {msg.text}
                                {msg.sender === 'bot' && msg.audioUrl && (
                                    <button 
                                        onClick={() => playAudio(msg.audioUrl)}
                                        className="audio-btn"
                                        title="Play message aloud"
                                    >
                                        <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                            <polygon points="11 5 6 9 2 9 2 15 6 15 11 19 11 5"></polygon>
                                            <path d="M19.07 4.93a10 10 0 0 1 0 14.14M15.54 8.46a5 5 0 0 1 0 7.07"></path>
                                        </svg>
                                    </button>
                                )}
                            </div>
                        </div>
                    ))}
                    {isTyping && (
                        <div className="chat-message bot">
                            <div className="typing-indicator-label">Give me a moment — I’m listening.</div>
                            <div className="typing-indicator">
                                <span></span>
                                <span></span>
                                <span></span>
                            </div>
                        </div>
                    )}
                    <div ref={chatEndRef} className="scroll-anchor" />
                </div>
            </div>

            <div className="input-area-full">
                <div className="input-container-full">
                    <button 
                        className={`mic-btn ${isListening ? 'listening' : ''}`}
                        onClick={toggleListening}
                        title={isListening ? "Listening... click to stop" : "Dictate message"}
                    >
                        {isListening ? (
                            <div className="mic-listening-pulse"></div>
                        ) : (
                            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                <path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"></path>
                                <path d="M19 10v2a7 7 0 0 1-14 0v-2"></path>
                                <line x1="12" y1="19" x2="12" y2="23"></line>
                                <line x1="8" y1="23" x2="16" y2="23"></line>
                            </svg>
                        )}
                    </button>
                    <input
                        type="text"
                        value={input}
                        onChange={(e) => setInput(e.target.value)}
                        onKeyPress={handleKeyPress}
                        placeholder={isListening ? "Listening..." : "Share what's on your mind... I'm listening."}
                        disabled={isTyping}
                        className="chat-input-full"
                    />
                    <button
                        onClick={sendMessage}
                        disabled={isTyping || !input.trim()}
                        className="send-btn-full"
                    >
                        {isTyping ? (
                            <div className="sending-indicator">
                                <span></span>
                                <span></span>
                                <span></span>
                            </div>
                        ) : (
                            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                                <path d="M22 2L11 13" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                                <path d="M22 2L15 22L11 13L2 9L22 2Z" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                            </svg>
                        )}
                    </button>
                </div>
            </div>
        </div>
    );
}

export default Chat;
